struct TimeMap { black_map: std::collections::HashMap<String, Vec<(i32, String)>> } impl TimeMap { fn new() -> Self { Self { black_map: std::collections::HashMap::new() } } fn set(&mut self, key: String, value: String, timestamp: i32) { self.black_map.entry(key).or_default().push((timestamp, value)); } fn get(&self, key: String, timestamp: i32) -> String { if let Some(v) = self.black_map.get(&key) { let idx = v.partition_point(|x| x.0 <= timestamp); if idx > 0 { return v[idx - 1].1.clone(); } } "".to_string() } }